#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e5+5;
int n,m,Q;
int Ls[N],lscnt;
int dfn[N],dfncnt;
int Fa[N],dep[N];
int sz[N],wc[N],top[N];
int tr[N],ans[N];
vector<int> g[N];
struct node{
    int opt,id,x,y,lca,val,key;
}q[N],q1[N],q2[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS1(int u,int fa){
    Fa[u]=fa,sz[u]=1;
    dep[u]=dep[fa]+1;
    for(int v:g[u])if(v^fa){
        DFS1(v,u),sz[u]+=sz[v];
        if(sz[v]>sz[wc[u]])wc[u]=v;
    }return;
}
void DFS2(int u,int Top){
    dfn[u]=++dfncnt,top[u]=Top;
    if(wc[u])DFS2(wc[u],Top);
    for(int v:g[u])
        if(v^Fa[u]&&v^wc[u])DFS2(v,v);return;
}
int LCA(int x,int y){
    while(top[x]!=top[y]){
        //cout<<top[x]<<" "<<top[y]<<"\n";
        if(dep[top[x]]>dep[top[y]])x=Fa[top[x]];
        else y=Fa[top[y]];
    }

    return (dep[x]<dep[y]?x:y);
}
bool cmp(int x,int y){return (x>y);}
void upd(int x,int k){while(x<=n)tr[x]+=k,x+=x&-x;return;}
int ask(int x){int sum=0;while(x)sum+=tr[x],x-=x&-x;return sum;}
void solve(int l,int r,int L,int R){
    if(L>R)return;bool can=0;
    for(int i=L;i<=R;i++)if(q[i].opt==2)can=1;
    if(!can)return;
    if(l==r){
        for(int i=L;i<=R;i++)
            if(q[i].opt==2)ans[q[i].id]=l;
        return;
    }
    int mid=(l+r)>>1,p1=0,p2=0,now_cnt=0;
    for(int i=L;i<=R;i++)
        if(q[i].opt==2){
            int u=q[i].x;
            int tmp=ask(dfn[u]+sz[u]-1)-ask(dfn[u]-1);
            if(tmp==now_cnt)q2[++p2]=q[i];
            else q1[++p1]=q[i];
        }else if(q[i].val<=mid){
            int ad=q[i].key;now_cnt+=ad;
            upd(dfn[q[i].x],ad),upd(dfn[q[i].y],ad);
            upd(dfn[q[i].lca],-ad);
            if(q[i].lca!=1)upd(dfn[Fa[q[i].lca]],-ad);
            q1[++p1]=q[i];
        }else q2[++p2]=q[i];
    for(int i=1;i<=p1;i++)if(q1[i].opt<2){
        int ad=q1[i].key;
        upd(dfn[q1[i].x],-ad),upd(dfn[q1[i].y],-ad);
        upd(dfn[q1[i].lca],ad);
        if(q1[i].lca!=1)upd(dfn[Fa[q1[i].lca]],ad);
    }
    for(int i=1;i<=p1;i++)q[L+i-1]=q1[i];
    for(int i=1;i<=p2;i++)q[R-p2+i]=q2[i];
    solve(l,mid,L,L+p1-1);
    solve(mid+1,r,R-p2+1,R);return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<n;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }DFS1(1,0);DFS2(1,1);
    for(int i=1;i<=m;i++){
        int opt=read();
        if(opt==2){
            int x=read();
            q[i]={2,++Q,x,0,0,0,0};
        }else if(opt==0){
            int x=read(),y=read(),k=read();
            q[i]={0,0,x,y,LCA(x,y),k,1};
            Ls[++lscnt]=-k;
        }else{
            int t=read();q[i]=q[t];
            q[i].key=-1,q[i].opt=1;
        }
    }Ls[++lscnt]=1;
    sort(Ls+1,Ls+lscnt+1);
    lscnt=unique(Ls+1,Ls+lscnt+1)-Ls-1;
    for(int i=1;i<=m;i++)if(q[i].opt<2)
        q[i].val=lower_bound(Ls+1,Ls+lscnt+1,-q[i].val)-Ls;
    for(int i=1;i<=lscnt;i++)Ls[i]=-Ls[i];
    solve(1,lscnt,1,m);
    for(int i=1;i<=Q;i++)cout<<Ls[ans[i]]<<"\n";
    return 0;
}
